// Build the causal-extraction brief.
// We trim each headline tightly (title only, no body), cap at 24 items,
// and pass the live universe so the LLM is *biased* toward valid symbols.
// The verifier still re-checks every symbol after extraction.
const news     = $('GET recent news (6h, urgency≥2)').first()?.json?.rows || [];
const universe = ($('GET universe (7d)').first()?.json?.symbols || [])
                   .map(s => String(s).toUpperCase());

if (!news.length) {
  return [{ json: { skip: true, reason: 'no news in window (6h, urgency≥2)' } }];
}
if (!universe.length) {
  return [{ json: { skip: true, reason: 'universe empty (no recent ticks)' } }];
}

// Deduplicate near-identical titles within the same source (poor man's
// near-dup filter — same first 80 chars + same source = one item).
const seen = new Set();
const items = [];
for (const r of news) {
  const key = String(r.source || '').toLowerCase() + '|' + String(r.title || '').slice(0, 80).toLowerCase();
  if (seen.has(key)) continue;
  seen.add(key);
  items.push({
    id:        r.id,
    ts:        r.ts,
    source:    r.source,
    symbols:   Array.isArray(r.symbols) ? r.symbols.slice(0, 6) : [],
    sentiment: r.sentiment,
    urgency:   r.urgency,
    title:     String(r.title || '').slice(0, 240),
  });
  if (items.length >= 24) break;
}

return [{ json: {
  skip: false,
  brief_items: items,
  universe,
} }];

// Verifier: parse JSON, validate every theme, drop symbols that aren't
// in the live universe (instead of rejecting the whole theme — partial
// extraction is more useful than nothing). Emits one item per accepted
// theme so the next HTTP node posts each separately to /rag/relation.
const brief    = $('Build brief').item.json;
const universe = new Set((brief.universe || []).map(s => String(s).toUpperCase()));
const evidenceById = new Set((brief.brief_items || []).map(it => String(it.id)));

const llmResp = $json;
let raw = '';
let parsed = null;
try {
  raw = String(llmResp?.choices?.[0]?.message?.content || '').trim();
  const m = raw.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(m ? m[0] : raw);
} catch (e) {
  return [{ json: { skip: true, reason: 'invalid JSON from LLM', raw: raw.slice(0, 800) } }];
}
const themes = Array.isArray(parsed?.themes) ? parsed.themes : [];
if (!themes.length) {
  return [{ json: { skip: true, reason: 'no themes returned', raw: raw.slice(0, 600) } }];
}

const accepted = [];
const rejected = [];
for (let i = 0; i < themes.length && accepted.length < 6; i++) {
  const t = themes[i] || {};
  const errors = [];
  const theme = String(t.theme || '').trim();
  if (!theme) errors.push('empty theme');
  if (theme.length > 80) errors.push('theme too long');
  const conf = Number(t.confidence);
  if (!(conf >= 0 && conf <= 1)) errors.push('confidence out of range');
  // Hard floor: skip very low-confidence noise.
  if (conf < 0.3) errors.push('confidence < 0.3');
  if (errors.length) {
    rejected.push({ index: i, theme, errors });
    continue;
  }
  // Filter symbols to the live universe (do NOT reject the theme over this).
  const rawSyms = Array.isArray(t.symbols) ? t.symbols : [];
  const symbols = rawSyms
    .map(s => String(s).toUpperCase().trim())
    .filter(s => s && universe.has(s))
    .slice(0, 12);
  // Same for evidence_ids — must come from our brief.
  const evidence = (Array.isArray(t.evidence_ids) ? t.evidence_ids : [])
    .map(x => String(x))
    .filter(x => evidenceById.has(x))
    .slice(0, 8);
  // A theme with no verified symbols AND no verified evidence is too weak
  // to be a 'causal chain'; treat as noise.
  if (!symbols.length && !evidence.length) {
    rejected.push({ index: i, theme, errors: ['no verified symbols or evidence'] });
    continue;
  }
  accepted.push({ json: {
    skip: false,
    theme,
    payload: {
      theme,
      mechanism:    String(t.mechanism || '').slice(0, 180) || null,
      summary:      String(t.summary   || '').slice(0, 280),
      entities:     (Array.isArray(t.entities) ? t.entities : []).map(s => String(s).trim()).filter(Boolean).slice(0, 10),
      sectors:      (Array.isArray(t.sectors)  ? t.sectors  : []).map(s => String(s).trim()).filter(Boolean).slice(0, 6),
      symbols,
      evidence_ids: evidence,
      confidence:   conf,
      model:        'default',
    },
  } });
}
if (!accepted.length) {
  return [{ json: { skip: true, reason: 'all themes rejected', rejected, raw: raw.slice(0, 600) } }];
}
return accepted;
